import{_ as e,o as a,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Ads Advanced Configurations","description":"","frontmatter":{"title":"Ads Advanced Configurations","slug":"ads-advanced-configuration"},"headers":[],"relativePath":"marketer-hub/ads-advanced-configuration.md","filePath":"marketer-hub/ads-advanced-configuration.md"}'),o={name:"marketer-hub/ads-advanced-configuration.md"};function r(s,t,d,l,c,p){return a(),n("div",null,[...t[0]||(t[0]=[i('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Explore Branch’s new linking experience for <a href="https://help.branch.io/docs/create-web-links-1#view-and-manage-links" target="_blank" rel="noreferrer">Web Links</a> and <a href="https://help.branch.io/docs/create-app-links-new" target="_blank" rel="noreferrer">App Links</a>, which offer deep linking, flexible configuration, and link analysis across multiple platforms!</p></div><div class="warning custom-block"><p class="custom-block-title">Ads Integration Guide</p><p>Please refer to our <a href="./ad-partner-integration-guide.html">Ads Basics</a> guide before using any the advanced options below.</p></div><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="view-through-attribution-vta-with-impression-pixels" tabindex="-1">View-Through Attribution (VTA) with Impression Pixels <a class="header-anchor" href="#view-through-attribution-vta-with-impression-pixels" aria-label="Permalink to &quot;View-Through Attribution (VTA) with Impression Pixels&quot;">​</a></h3><p>View-through attribution allows you to track installs, session starts and conversion events back to an ad impression, even if the ad was never clicked on.</p><p>Our view-through attribution logic is currently as follows for any given event:</p><ul><li>If there&#39;s a click within a valid attribution window, give credit to the click.</li><li>If there&#39;s no click within a valid attribution window, give credit to the last impression that was within a valid attribution window.</li></ul><p>To create an impression tracking link for non-SAN networks, simply <a href="./ad-partner-integration-guide.html#4-create-ad-link">create an ad link</a>, and grab the impression link from the final step of link creation. SAN networks support VTA without any additional links.</p><h3 id="testing-with-setdebug" tabindex="-1">Testing with setDebug <a class="header-anchor" href="#testing-with-setdebug" aria-label="Permalink to &quot;Testing with setDebug&quot;">​</a></h3><p>When integrating the SDKs, it&#39;s often useful to use setDebug to verify that your app is able to communicate with Branch servers, and is receiving deep link data. However, our upstream systems don&#39;t register test events sent using setDebug, so events will not appear in Liveview or Analytics, nor will they fire Postbacks. You should disable setDebug when looking at Liveview or testing postbacks.</p><h3 id="server-to-server-ad-links" tabindex="-1">Server to Server Ad Links <a class="header-anchor" href="#server-to-server-ad-links" aria-label="Permalink to &quot;Server to Server Ad Links&quot;">​</a></h3><p>If you have a server to server integration you must provide specific requirements for attribution. Make sure to append the following mandatory key-values into tracking ad links to ensure they are not rejected or blocked:</p><ul><li><p><strong>Server to Server Parameter</strong>: Add server-to-server click macro URL parameter at the end of your link, so we know it&#39;s a server to server link:</p><ul><li><code>%24s2s=true</code></li></ul></li><li><p><strong>Device ID Macro Value</strong>: Pass user Advertising Identifier via click macro URL parameter:</p><ul><li><code>%24idfa={IDFA}</code> for iOS devices</li><li><code>%24aaid={AAID}</code> for Android devices</li></ul></li><li><p><strong>IP address</strong>: Pass user IP information in the header OR click macro URL parameter to override on click:</p><ul><li>HTTP header <code>x-ip-override: {IP_ADDRESS}</code></li><li>Click macro URL parameter: <code>device_ip={IP_ADDRESS}</code></li></ul></li><li><p><strong>User Agent</strong>: Pass User Agent information in the header OR click macro URL parameter to override on click:</p><ul><li>HTTP header <code>User-Agent: {USER_AGENT}</code></li><li>Click macro URL parameter: <code>user_agent={USER_AGENT}</code></li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Update Partner-specific URL macros</p><p>Please make sure that you are using your macros instead of {IDFA}. {AAID}, {IP_ADDRESS}, {USER_AGENT}</p></div><h3 id="adding-enabling-more-postbacks" tabindex="-1">Adding/Enabling More Postbacks <a class="header-anchor" href="#adding-enabling-more-postbacks" aria-label="Permalink to &quot;Adding/Enabling More Postbacks&quot;">​</a></h3><p>Basic postbacks are automatically activated for events like <em>Install</em> and <em>Purchase</em> when you enable your ad partner. You can then add additional postbacks, for example, if you wanted to add postbacks for custom events that are specific to your app like <em>Account Created</em>.</p><p>To add a postback:</p><ol><li><p>Under <strong>Partner Management</strong>, select the partner for whom you want to add/edit their postback.</p></li><li><p>Click on the <strong>Postback Config</strong> tab on said partner’s page.</p></li><li><p>Click the <strong>Add New Postback</strong> button at the bottom of the screen.</p></li><li><p>A modal will appear with Branch default events, as well as any commerce (reserved events like <em>PURCHASE)</em> or custom events you&#39;ve set up. Select an event, enter a postback URL if you&#39;re asked to, and click <strong>Save</strong>. This will be the event that triggers your new postback.</p><ol><li>NOTE: If Branch does not already have a postback template for a partner, please provide a valid URL for your partner.</li></ol></li></ol><h3 id="sending-all-events" tabindex="-1">Sending All Events <a class="header-anchor" href="#sending-all-events" aria-label="Permalink to &quot;Sending All Events&quot;">​</a></h3><p>If you want to send <strong>All Events</strong> - whether attributed to this partner or not - you can enable this setting by checking the <strong>All Events</strong> box on a per postback basis.</p><div class="warning custom-block"><p class="custom-block-title">Privacy Implications</p><p>As this setting will send <strong>All Events</strong> - with the name and customer event alias listed in this row, whether attributed to this partner or not - we recommend using caution when/if enabling, especially if you have enabled agencies to access your account.</p></div><h3 id="editing-templates" tabindex="-1">Editing Templates <a class="header-anchor" href="#editing-templates" aria-label="Permalink to &quot;Editing Templates&quot;">​</a></h3><p>In most cases, the default postback URL generated from your selections is sufficient to provide postback notification to interested parties.</p><p>But sometimes you may need/want to edit or remove a parameter from the postback URL, or append a macro expression/variable to include additional information.</p><div class="tip custom-block"><p class="custom-block-title">Example</p><p>You want to send your partner the actual items a user adds to their cart so they can optimize based off those items. Their current <strong>Add to Cart</strong> postback template does not include this information. Therefore, you need to add <a href="./postback-macros-functions.html#content-items-data">Content Items</a> macros to their URL. To do so, you’ll first need to get the correct field from the partner in which to pass this data; e.g. <code>cart_items</code>. Finally, you’d append <code>&amp;cart_item=${(content_items[0].$product_name)!}</code> to the postback template.</p></div><p>Please refer to <a href="./postback-macros-functions.html">Postback Macros &amp; Functions</a> when looking to append additional macros.</p><p>To edit the postback template:</p><ol><li><p>Under <strong>Partner Management</strong>, select the partner for whom you want to add/edit their postback.</p></li><li><p>Click on the <strong>Postback Config</strong> tab on said partner’s page.</p></li><li><p>In the <strong>Postback URL</strong> field, add/edit/remove the key-value pairs necessary.</p><ol><li>You must include a <code>&amp;</code> before each key-value pairs you append.</li></ol></li><li><p>Click <strong>Save</strong>.</p></li><li><p>Alternatively, hover on the three dots icon to the right of the postback and click <strong>Advanced Edit</strong>.</p></li><li><p>In the <strong>Send a Webhook to</strong> field, add/edit/remove the key-value pairs necessary.</p><ol><li>You must include a <code>&amp;</code> before each key-value pairs you append.</li></ol></li><li><p>Click <strong>Save</strong>.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">Reset Postbacks</p><p>We all make mistakes from time to time. If you need to reset your postbacks and your credentials, navigate to the <strong>Account Settings</strong> tab and look for the <strong>Reset all settings</strong> button. Be careful though! This will disable the ad partner, clear out all credentials and postbacks that you&#39;ve set up, and return the ad partner to its basic configuration. You can then start afresh.</p></div><h2 id="granting-agency-access" tabindex="-1">Granting Agency Access <a class="header-anchor" href="#granting-agency-access" aria-label="Permalink to &quot;Granting Agency Access&quot;">​</a></h2><h3 id="granting-ad-partner-access" tabindex="-1">Granting Ad Partner Access <a class="header-anchor" href="#granting-ad-partner-access" aria-label="Permalink to &quot;Granting Ad Partner Access&quot;">​</a></h3><p>To grant an Ad Partner access to your App&#39;s data, you need to add them as an <code>agency</code> in your Branch account. Doing so gives said ad partner access to your app; based on the permissions you define.</p><ol><li><p>Go to <strong>Account Settings</strong> and click on the <strong>Agencies</strong> tab.</p></li><li><p>On the <strong>Agencies</strong> tab, click the <strong>Add New Agency</strong> button.</p></li><li><p>In the <strong>Add New Agency</strong> modal:</p><ol><li><p>Select the Agency name from the drop-down.</p></li><li><p>Select the appropriate level of access.</p><ul><li><strong>Admin</strong> - Edit access to all settings and export access to all data.</li><li><strong>Team Member</strong> - Edit access to channels and links, read-only access to app settings, and access to aggregate data.</li><li><strong>Full Read</strong> - Read-only access to all settings and access to aggregate data.</li><li><strong>Limited Read</strong> - Access to aggregate data only.</li><li><strong>Custom</strong> - Customize settings and data access.</li><li><strong>No Access</strong> - no dashboard access.</li></ul></li><li><p>Click &quot;Invite&quot;.</p></li><li><p>All Agency Admins on the agency account will receive an invitation email, and any of those Agency Admins can accept the invitation on behalf of their agency.</p></li></ol></li></ol><div class="warning custom-block"><p class="custom-block-title">Granting agencies Sensitive Data &amp; App-Level Settings permissions</p><p>Agencies with Sensitive Data &amp; App-Level Settings permissions to an Org or App will have access to that Org/App&#39;s API keys, which can be used to access Branch&#39;s <a href="https://help.branch.io/apidocs/deep-linking-api" target="_blank" rel="noreferrer">HTTP</a> and <a href="https://help.branch.io/apidocs/daily-exports-api" target="_blank" rel="noreferrer">Data Export</a> APIs. Agency data filters (e.g. Only Show Agency-tagged Data) will not apply to data accessed via the Daily Export API, so we recommend against granting agencies these permissions and providing them with API keys.</p></div><h3 id="defining-permissions" tabindex="-1">Defining Permissions <a class="header-anchor" href="#defining-permissions" aria-label="Permalink to &quot;Defining Permissions&quot;">​</a></h3><p>Each access level - as defined above - comes with predefined permissions which you can edit if you choose.</p><div class="tip custom-block"><p class="custom-block-title">Modifying Permissions</p><p>If you want to modify a predefined access level, click the pencil icon to (de)select the available options.</p></div><ul><li><strong>Link-level Settings</strong> - Settings or features that can impact functionality for single links.</li><li><strong>Channel-level Settings</strong> - Settings or features that can impact functionality across a marketing channel.</li><li><strong>App-level Settings</strong> - Settings or features that can impact functionality app-wide.</li><li><strong>Aggregate Data</strong> - Summary data that contains no granular data.</li><li><strong>Sensitive Data</strong> - Data that can contain user-identifying, payment-related, or secret information.</li></ul><h4 id="additional-data-filters" tabindex="-1">Additional Data Filters <a class="header-anchor" href="#additional-data-filters" aria-label="Permalink to &quot;Additional Data Filters&quot;">​</a></h4><p>During the process of granting an agency access to your Branch account, you can also impose limitations around what data is available to the agency at any given time.</p><div class="warning custom-block"><p class="custom-block-title">Filter to Only Show Data from Specific Ad Networks</p><p>When giving an ad partner access to your Branch account, please make sure you toggle the <strong>Only Show Data from Specific Ad Networks</strong> to on and select the ad partner you are giving access to.</p></div><ul><li><strong>Only Show Agency-tagged Data</strong> - When toggled on, agency users can only see events tagged with their Agency ID.</li><li><strong>Restrict Access to Revenue Data</strong> - When toggled on, agency users cannot view revenue data.</li><li><strong>Only Show Data from Specific Ad Networks</strong> - When toggled on, agency users can only view events from a specific list of ad networks.</li><li><strong>Only Show Data from Specific Locations</strong> - When toggled on, agency users can only view events that have taken place in a specific list of countries.</li></ul><div class="warning custom-block"><p class="custom-block-title">Agency Invitation</p><p>Once you&#39;ve defined the appropriate levels of access for your Agency, you must <strong>Invite</strong> them to access the Branch dashboard. Only Organization Admins can invite an Agency to access the Branch dashboard.</p></div><h2 id="tracking-link-parameters" tabindex="-1">Tracking Link Parameters <a class="header-anchor" href="#tracking-link-parameters" aria-label="Permalink to &quot;Tracking Link Parameters&quot;">​</a></h2><p>Branch Tracking links allow tracking many parameters about the performance of your ad campaigns and individual ads. You can see each partner&#39;s specific link Parameters under the <strong>Link Parameters</strong> tab:</p><p>Additional parameters for advanced analysis may be added to the link after the &#39;?&#39; or &#39;&amp;&#39; character, to trace extra information.</p><div class="tip custom-block"><p class="custom-block-title">Example Tracking Link with Additional Parameters</p><p>Example Branch link including additional parameters to pass Agency and Sub Publisher information:<code>https://tracking.app.link?$3p=a_partner&amp;~agency_id=1234&amp;~agency=myAgency&amp;~secondary_publisher=best_publisher</code></p></div><p>The following parameters are available to use within the pre-generated tracking link:</p><h3 id="campaign-information" tabindex="-1">Campaign Information <a class="header-anchor" href="#campaign-information" aria-label="Permalink to &quot;Campaign Information&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Branch Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>~agency</code></td><td>Agency name</td></tr><tr><td><code>~agency_id</code></td><td><a href="https://help.branch.io/partners-portal/docs/manage-agency-user-profile" target="_blank" rel="noreferrer">Agency ID</a></td></tr><tr><td><code>~secondary_publisher</code></td><td>Sub Publisher</td></tr><tr><td><code>~campaign</code></td><td>Campaign name</td></tr><tr><td><code>~campaign_id</code></td><td>Campaign ID</td></tr><tr><td><code>~channel</code></td><td>Channel</td></tr><tr><td><code>~feature</code></td><td>Feature</td></tr><tr><td><code>~stage</code></td><td>Stage</td></tr><tr><td><code>~tags</code></td><td>Tags</td></tr><tr><td><code>~creative_name</code></td><td>Creative name</td></tr><tr><td><code>~creative_id</code></td><td>Creative ID</td></tr><tr><td><code>~ad_set_name</code></td><td>Ad set name</td></tr><tr><td><code>~ad_set_id</code></td><td>Ad set ID</td></tr><tr><td><code>~ad_name</code></td><td>Ad unit name</td></tr><tr><td><code>~ad_id</code></td><td>Ad unit ID</td></tr><tr><td><code>~banner_dimensions</code></td><td>Banner Dimension</td></tr><tr><td><code>~placement</code></td><td>Placement</td></tr><tr><td><code>~keyword_id</code></td><td>Keyword ID</td></tr><tr><td><code>~keyword_text</code></td><td>Keyword Text</td></tr></tbody></table><h4 id="device-information" tabindex="-1">Device Information <a class="header-anchor" href="#device-information" aria-label="Permalink to &quot;Device Information&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Branch Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>%24aaid</code></td><td>Google AAID</td></tr><tr><td><code>%24idfa</code></td><td>Apple IDFA</td></tr></tbody></table><h3 id="spend-calculation" tabindex="-1">Spend Calculation <a class="header-anchor" href="#spend-calculation" aria-label="Permalink to &quot;Spend Calculation&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Cost Data Availability</p><p>Cost data passed via these macros is available in exports but is not visible in the Branch dashboard.</p></div><table tabindex="0"><thead><tr><th>Branch Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>~cost_model</code></td><td>Cost Model; e.g. CPI, eCPC</td></tr><tr><td><code>~cost</code></td><td>Cost; e.g. 10.00</td></tr><tr><td><code>~cost_currency</code></td><td>Cost Currency; e.g. USD</td></tr></tbody></table><h2 id="attribution-windows" tabindex="-1">Attribution Windows <a class="header-anchor" href="#attribution-windows" aria-label="Permalink to &quot;Attribution Windows&quot;">​</a></h2><h3 id="changing-attribution-windows" tabindex="-1">Changing Attribution Windows <a class="header-anchor" href="#changing-attribution-windows" aria-label="Permalink to &quot;Changing Attribution Windows&quot;">​</a></h3><p>Attribution windows can be specified at the global account level or on a per link basis with the link level window taking priority. See the below instructions for setup.</p><p>For customer experience and data accuracy, please do not set your deep linking window longer than the other attribution windows.</p><h3 id="account-level-attribution-windows" tabindex="-1">Account Level Attribution Windows <a class="header-anchor" href="#account-level-attribution-windows" aria-label="Permalink to &quot;Account Level Attribution Windows&quot;">​</a></h3><p>You can edit your attribution windows under Link Settings &gt; Attribution Windows.</p><p>Learn more about account level attribution windows in <a href="./branch-attribution-logic-settings.html">People-Based Attribution</a>.</p><h3 id="ad-network-attribution-windows" tabindex="-1">Ad Network Attribution Windows <a class="header-anchor" href="#ad-network-attribution-windows" aria-label="Permalink to &quot;Ad Network Attribution Windows&quot;">​</a></h3><p>You can edit your attribution windows at the ad network level if your ad network requires it. This is recommended when you enable networks like Facebook and Google, which may have different windows for installs. With this, you can preserve your Account Level Attribution Windows, as well.</p><h3 id="link-level-attribution-windows" tabindex="-1">Link Level Attribution Windows <a class="header-anchor" href="#link-level-attribution-windows" aria-label="Permalink to &quot;Link Level Attribution Windows&quot;">​</a></h3><p>To set attribution windows on a link level, you can append the following parameters to your generated Branch link.</p><table tabindex="0"><thead><tr><th>Key</th><th>Example Link</th></tr></thead><tbody><tr><td><code>$click_install_window_days</code></td><td>&amp;lt;<a href="https://branchster.app.link/hpNVE52gxE?$click_install_window_days=3%5C&amp;gt" target="_blank" rel="noreferrer">https://branchster.app.link/hpNVE52gxE?$click_install_window_days=3\\&amp;gt</a>;</td></tr><tr><td><code>$click_session_start_window_days</code></td><td>&amp;lt;<a href="https://branchster.app.link/hpNVE52gxE?$click_session_start_window_days=7%5C&amp;gt" target="_blank" rel="noreferrer">https://branchster.app.link/hpNVE52gxE?$click_session_start_window_days=7\\&amp;gt</a>;</td></tr><tr><td><code>$click_conversion_window_days</code></td><td>&amp;lt;<a href="https://branchster.app.link/hpNVE52gxE?$click_conversion_window_days=30%5C&amp;gt" target="_blank" rel="noreferrer">https://branchster.app.link/hpNVE52gxE?$click_conversion_window_days=30\\&amp;gt</a>;</td></tr><tr><td><code>$impression_install_window_days</code></td><td>&amp;lt;<a href="https://branchster.app.link/hpNVE52gxE?$impression_install_window_days=3%5C&amp;gt" target="_blank" rel="noreferrer">https://branchster.app.link/hpNVE52gxE?$impression_install_window_days=3\\&amp;gt</a>;</td></tr><tr><td><code>$impression_session_start_window_days</code></td><td>&amp;lt;<a href="https://branchster.app.link/hpNVE52gxE?$impression_session_start_window_days=1%5C&amp;gt" target="_blank" rel="noreferrer">https://branchster.app.link/hpNVE52gxE?$impression_session_start_window_days=1\\&amp;gt</a>;</td></tr><tr><td><code>$impression_conversion_window_days</code></td><td>&amp;lt;<a href="https://branchster.app.link/hpNVE52gxE?$impression_session_start_window_days=7%5C&amp;gt" target="_blank" rel="noreferrer">https://branchster.app.link/hpNVE52gxE?$impression_session_start_window_days=7\\&amp;gt</a>;</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Link Level Attribution Support for Standard Branch Links</p><p>As of July 2017, link level attribution window setting is only available on standard Branch Links. Special Branch Links such as the ones used for Google&#39;s Universal App Campaign or Play Store links with Branch link id parameters are currently not supported.</p></div><h3 id="view-your-data" tabindex="-1">View your data <a class="header-anchor" href="#view-your-data" aria-label="Permalink to &quot;View your data&quot;">​</a></h3><p>The <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics Page</a> on the Branch dashboard shows the performance of your ad campaigns <em>across both web and app</em>. You can view performance over time, including purchase and other custom events.</p><p>Events are attributed using Branch&#39;s unified last-click attribution model. This means that Branch will attribute to the last click across channels, and across platforms.</p><p>For example, if a customer clicks a Branch email link, and then clicks an ad, installs the app and purchases an item, Branch will attribute the install and the purchase to the last clicked ad link.</p><p>If the customer then goes on to purchase an item on web within the attribution window, Branch will also attribute the web purchase to the same ad link, connecting the web and app actions taken by a single user for a more accurate view of your marketing channels and customer behavior.</p><p>You can read more about <a href="./branch-attribution-logic-settings.html">Branch&#39;s Attribution logic here</a>.</p>',74)])])}const u=e(o,[["render",r]]);export{g as __pageData,u as default};
